function hasProgress(saved){return !!saved&&(saved.introSeen===true||saved.money!==defaults.money||saved.reputation!==defaults.reputation||saved.machines!==defaults.machines||saved.day!==defaults.day||saved.minutes!==defaults.minutes||saved.quest>0||saved.brokenFixed||saved.repairStage!=="not_started"||saved.playerX!==defaults.playerX||saved.playerY!==defaults.playerY||saved.foundParts?.length||saved.expansions?.length||Object.values(saved.parts||{}).some(Boolean));}
function loadState(){try{const raw=localStorage.getItem(SAVE_KEY);if(!raw)return {...defaults,parts:{...defaults.parts}};const saved=JSON.parse(raw)||{};if(!hasProgress(saved)){saveExists=false;return {...defaults,parts:{...defaults.parts}};}saveExists=true;const loaded={...defaults,...saved,parts:{...defaults.parts,...(saved.parts||{})},introSeen:true};loaded.machines=Math.min(MAX_MACHINES,Math.max(1,Number(loaded.machines)||defaults.machines));if(loaded.brokenFixed){loaded.repairStage="complete";loaded.machines=Math.min(MAX_MACHINES,Math.max(2,loaded.machines));}else if(loaded.quest>0&&loaded.repairStage==="not_started")loaded.repairStage="gathering";return loaded;}catch{saveExists=false;return {...defaults,parts:{...defaults.parts}};}}
function saveState(){if(!gameStarted||resettingSave)return;state.playerX=Math.round(playerPosition.x);state.playerY=Math.round(playerPosition.y);localStorage.setItem(SAVE_KEY,JSON.stringify(state));saveExists=true;}
function updateHUD(){document.getElementById("money").textContent=Math.floor(state.money);document.getElementById("reputation").textContent=Math.round(state.reputation);document.getElementById("machines").textContent=state.machines;renderMachineBank();Object.keys(state.parts).forEach(part=>{const el=document.getElementById(`part-${part}`);if(el)el.textContent=state.parts[part];});document.getElementById("journal-alert").style.display=state.repairStage==="complete"&&!state.serviceNeeded?"none":"grid";const clean=Math.max(0,Math.round(state.restroomCleanliness));document.getElementById("cleanliness-fill").style.width=`${clean}%`;document.getElementById("restroom-status").textContent=clean>70?"SPARKLING":clean>35?"NEEDS A SWEEP":"OH DEAR";document.getElementById("restroom-status").style.color=clean>70?"#c7f3dc":clean>35?"#ffe17c":"#ff9b9b";document.getElementById("happiness-score").textContent=Math.round(state.visitorHappiness);updateAchievements();saveState();}
function toast(text,duration=2300){const el=document.getElementById("toast");el.textContent=text;el.classList.add("show");clearTimeout(toastTimer);toastTimer=setTimeout(()=>el.classList.remove("show"),duration);}

function enterCasino(){gameStarted=true;lastFrame=performance.now();document.getElementById("start-menu").classList.add("done");document.getElementById("intro").classList.add("done");saveState();}
function startNewCasino(){if(saveExists&&!confirm("Start a new casino? This will overwrite the current saved casino."))return;resettingSave=true;gameStarted=false;localStorage.removeItem(SAVE_KEY);location.reload();}
function showDeleteSaveConfirm(){document.getElementById("delete-save-confirm").classList.remove("hidden");}
function hideDeleteSaveConfirm(){document.getElementById("delete-save-confirm").classList.add("hidden");}
function deleteSavedGame(){resettingSave=true;gameStarted=false;localStorage.removeItem(SAVE_KEY);location.reload();}
