function ensureAudio(){if(!audioContext)audioContext=new(window.AudioContext||window.webkitAudioContext)();if(audioContext.state==="suspended")audioContext.resume();if(!musicTimer)startMusic();}
function tone(freq,duration=.12,type="sine",volume=.08){if(!audioContext||!state.sfx)return;const o=audioContext.createOscillator(),g=audioContext.createGain();o.frequency.value=freq;o.type=type;g.gain.setValueAtTime(volume*state.sfx/100,audioContext.currentTime);g.gain.exponentialRampToValueAtTime(.001,audioContext.currentTime+duration);o.connect(g).connect(audioContext.destination);o.start();o.stop(audioContext.currentTime+duration);}
function startMusic(){const bpm=132,beat=60/bpm,swing=.64,bass=[130.81,146.83,164.81,174.61,196,185,174.61,164.81,146.83,164.81,174.61,196,146.83,164.81,196,220],chords=[[261.63,329.63,392,493.88],[220,277.18,329.63,415.3],[293.66,349.23,440,523.25],[196,246.94,293.66,392]],noise=audioContext.createBuffer(1,audioContext.sampleRate*.06,audioContext.sampleRate);let next=0,step=0;const data=noise.getChannelData(0);for(let i=0;i<data.length;i++)data[i]=(Math.random()*2-1)*(1-i/data.length);const note=(freq,t,dur,type,gain)=>{const o=audioContext.createOscillator(),g=audioContext.createGain();o.type=type;o.frequency.setValueAtTime(freq,t);g.gain.setValueAtTime(.0001,t);g.gain.exponentialRampToValueAtTime(gain*state.music/100,t+.025);g.gain.exponentialRampToValueAtTime(.0001,t+dur);o.connect(g).connect(audioContext.destination);o.start(t);o.stop(t+dur+.04);};const brush=(t,gain=.018)=>{const s=audioContext.createBufferSource(),g=audioContext.createGain(),f=audioContext.createBiquadFilter();s.buffer=noise;f.type="highpass";f.frequency.value=1600;g.gain.setValueAtTime(gain*state.music/100,t);g.gain.exponentialRampToValueAtTime(.0001,t+.055);s.connect(f).connect(g).connect(audioContext.destination);s.start(t);};const playStep=(t,n)=>{const eighth=n%16,quarter=n%2===0,bar=Math.floor(n/16)%chords.length;if(quarter)note(bass[(n/2)%bass.length],t,.28,"sine",.055);if([3,7,11,15].includes(eighth)){chords[bar].forEach((freq,i)=>note(freq*(i===3?2:1),t+i*.012,.22,"triangle",.012));note(chords[bar][2]*2,t+.02,.32,"sine",.01);}if(eighth%2===1)brush(t,.01);if(eighth===4||eighth===12){note(880,t,.045,"square",.006);brush(t,.022);}};musicTimer=setInterval(()=>{if(!audioContext)return;const now=audioContext.currentTime;if(!state.music){next=now+.05;return;}if(!next||next<now)next=now+.04;while(next<now+.25){playStep(next,step);next+=step%2===0?beat*swing:beat*(1-swing);step++;}},50);}
document.getElementById("sound-toggle").onclick=()=>{ensureAudio();state.music=state.music?0:20;document.getElementById("sound-toggle").textContent=state.music?"🔊":"🔇";saveState();};
