const key=(c,r)=>`${c},${r}`;
function tileRect(c,r,w=1,h=1){return {x:GRID.x+c*GRID.t,y:GRID.y+r*GRID.t,w:w*GRID.t,h:h*GRID.t};}
function tileCenter(c,r){return {x:GRID.x+c*GRID.t+GRID.t/2,y:GRID.y+r*GRID.t+GRID.t/2};}
function setTile(c,r,type){if(c>=0&&c<GRID.cols&&r>=0&&r<GRID.rows)tileMap.set(key(c,r),type);}
function fillTiles(c,r,w,h,type){for(let y=r;y<r+h;y++)for(let x=c;x<c+w;x++)setTile(x,y,type);}
function tileType(c,r){return tileMap.get(key(c,r))||TILE.wall;}
function isPublicWalkable(type){return type===TILE.floor||type===TILE.door;}
function canUseTile(type,opts={}){return isPublicWalkable(type)||(type===TILE.staff&&opts.allowStaff);}
function canRouteTile(type,opts={}){return type===TILE.floor||type===TILE.door||(type===TILE.staff&&opts.allowStaff);}
function canOccupyTile(c,r,opts={}){return canUseTile(tileType(c,r),opts);}
function outlineRoom(c,r,w,h){fillTiles(c,r,w,1,TILE.wall);fillTiles(c,r+h-1,w,1,TILE.wall);fillTiles(c,r,1,h,TILE.wall);fillTiles(c+w-1,r,1,h,TILE.wall);}
